     1→const express = require('express');
     2→const pool    = require('../db');
     3→
     4→// Per-table column whitelists — prevents column-name injection
     5→const ALLOWED_COLUMNS = {
     6→  projects:         ['name','client','status','progress','budget','spent','start_date','end_date','manager','location','type','phase','workers','contract_value','description'],
     7→  invoices:         ['number','client','project_id','project','amount','vat','cis_deduction','status','issue_date','due_date','description'],
     8→  safety_incidents: ['type','title','severity','status','project_id','project','reported_by','reported_by_name','date','location','description','root_cause','corrective_actions','injured_party','immediate_actions'],
     9→  rfis:             ['number','project_id','project','subject','question','priority','status','submitted_by','submitted_date','due_date','assigned_to','response'],
    10→  change_orders:    ['number','project_id','project','title','description','amount','status','submitted_date','approved_date','reason','schedule_impact'],
    11→  team_members:     ['name','role','trade','email','phone','status','cis_status','utr_number','ni_number','hours_this_week','rams_completed'],
    12→  equipment:        ['name','type','registration','status','location','next_service','daily_rate','hire_period'],
    13→  subcontractors:   ['company','trade','contact','email','phone','status','cis_verified','insurance_expiry','rams_approved','current_project','contract_value','rating'],
    14→  documents:        ['name','type','project_id','project','uploaded_by','version','size','status','category'],
    15→  timesheets:       ['worker_id','worker','project_id','project','week','regular_hours','overtime_hours','daywork_hours','total_pay','status','cis_deduction'],
    16→  meetings:         ['title','meeting_type','project_id','project','date','time','location','attendees','agenda','minutes','actions','status','link'],
    17→  materials:        ['name','category','quantity','unit','unit_cost','total_cost','supplier','project_id','project','status','delivery_date','po_number'],
    18→  punch_list:       ['project_id','project','location','description','assigned_to','priority','status','due_date','photos','trade'],
    19→  inspections:      ['type','project_id','project','inspector','date','status','score','items','next_inspection'],
    20→  rams:             ['title','project_id','project','activity','version','status','created_by','approved_by','review_date','hazards','method_statement','ppe','signatures','required'],
    21→  cis_returns:      ['contractor','utr','period','gross_payment','materials_cost','labour_net','cis_deduction','status','verification_status'],
    22→  tenders:          ['title','client','value','deadline','status','probability','type','location','ai_score','notes'],
    23→  contacts:         ['name','company','role','email','phone','type','value','last_contact','status','projects'],
    24→  risk_register:    ['title','project_id','project','category','likelihood','impact','owner','status','mitigation','review_date'],
    25→  purchase_orders:  ['number','supplier','project_id','project','amount','status','order_date','delivery_date','items','notes'],
    26→  daily_reports:    ['project_id','project','date','prepared_by','weather','temperature','workers_on_site','activities','materials','equipment','issues','photos','progress'],
    27→};
    28→
    29→/**
    30→ * Creates a standard CRUD router for any table.
    31→ * @param {string} tableName - The PostgreSQL table name
    32→ * @param {string} [orderCol='created_at'] - Column to order by
    33→ */
    34→function makeRouter(tableName, orderCol = 'created_at') {
    35→  const router  = express.Router();
    36→  const allowed = ALLOWED_COLUMNS[tableName] || [];
    37→
    38→  function filterKeys(data) {
    39→    return Object.keys(data).filter(k => allowed.includes(k) && data[k] !== undefined);
    40→  }
    41→
    42→  // GET / — list all
    43→  router.get('/', async (req, res) => {
    44→    try {
    45→      const { rows } = await pool.query(`SELECT * FROM ${tableName} ORDER BY ${orderCol} DESC`);
    46→      res.json(rows);
    47→    } catch (err) {
    48→      console.error(`[GET ${tableName}]`, err.message);
    49→      res.status(500).json({ message: err.message });
    50→    }
    51→  });
    52→
    53→  // GET /:id — get one
    54→  router.get('/:id', async (req, res) => {
    55→    try {
    56→      const { rows } = await pool.query(`SELECT * FROM ${tableName} WHERE id = $1`, [req.params.id]);
    57→      if (!rows[0]) return res.status(404).json({ message: 'Not found' });
    58→      res.json(rows[0]);
    59→    } catch (err) {
    60→      res.status(500).json({ message: err.message });
    61→    }
    62→  });
    63→
    64→  // POST / — create
    65→  router.post('/', async (req, res) => {
    66→    const keys = filterKeys(req.body);
    67→    if (!keys.length) return res.status(400).json({ message: 'No valid fields provided' });
    68→
    69→    const cols         = keys.join(', ');
    70→    const placeholders = keys.map((_, i) => `$${i + 1}`).join(', ');
    71→    const values       = keys.map(k => req.body[k]);
    72→
    73→    try {
    74→      const { rows } = await pool.query(
    75→        `INSERT INTO ${tableName} (${cols}) VALUES (${placeholders}) RETURNING *`,
    76→        values
    77→      );
    78→      res.status(201).json(rows[0]);
    79→    } catch (err) {
    80→      console.error(`[POST ${tableName}]`, err.message);
    81→      res.status(500).json({ message: err.message });
    82→    }
    83→  });
    84→
    85→  // PUT /:id — update
    86→  router.put('/:id', async (req, res) => {
    87→    const keys = filterKeys(req.body);
    88→    if (!keys.length) return res.status(400).json({ message: 'No valid fields provided' });
    89→
    90→    const setClause = keys.map((k, i) => `${k} = $${i + 1}`).join(', ');
    91→    const values    = [...keys.map(k => req.body[k]), req.params.id];
    92→
    93→    try {
    94→      const { rows } = await pool.query(
    95→        `UPDATE ${tableName} SET ${setClause} WHERE id = $${keys.length + 1} RETURNING *`,
    96→        values
    97→      );
    98→      if (!rows[0]) return res.status(404).json({ message: 'Not found' });
    99→      res.json(rows[0]);
   100→    } catch (err) {
   101→      console.error(`[PUT ${tableName}]`, err.message);
   102→      res.status(500).json({ message: err.message });
   103→    }
   104→  });
   105→
   106→  // DELETE /:id
   107→  router.delete('/:id', async (req, res) => {
   108→    try {
   109→      const { rowCount } = await pool.query(`DELETE FROM ${tableName} WHERE id = $1`, [req.params.id]);
   110→      if (!rowCount) return res.status(404).json({ message: 'Not found' });
   111→      res.json({ message: 'Deleted successfully' });
   112→    } catch (err) {
   113→      res.status(500).json({ message: err.message });
   114→    }
   115→  });
   116→
   117→  return router;
   118→}
   119→
   120→module.exports = makeRouter;
   121→

