    12→// POST /api/auth/login
    13→router.post('/login', async (req, res) => {
    14→  const { email, password } = req.body;
    15→  if (!email || !password) return res.status(400).json({ message: 'Email and password required' });
    16→
    17→  try {
    18→    const { rows } = await pool.query('SELECT * FROM users WHERE email = $1', [email.toLowerCase().trim()]);
    19→    const user = rows[0];
    20→    if (!user) return res.status(401).json({ message: 'Invalid email or password' });
    21→
    22→    const valid = await bcrypt.compare(password, user.password_hash);
    23→    if (!valid) return res.status(401).json({ message: 'Invalid email or password' });
    24→
    25→    const token = jwt.sign(
    26→      { id: user.id, email: user.email, role: user.role, name: user.name, company: user.company },
    27→      SECRET,
    28→      { expiresIn: '7d' }
    29→    );
    30→
    31→    const { password_hash, ...safeUser } = user;
    32→    res.json({ token, user: safeUser });
    33→  } catch (err) {
    34→    console.error('[auth/login]', err);
    35→    res.status(500).json({ message: 'Server error' });
    36→  }
    37→});
    38→
