    20→async function handleProjects() {
    21→  const { rows } = await pool.query(
    22→    `SELECT name, client, status, progress, budget, spent, manager, location FROM projects ORDER BY created_at DESC`
    23→  );
    24→  if (!rows.length) {
    25→    return {
    26→      reply: 'No projects found in the database.',
    27→      data: { count: 0 },
    28→      suggestions: [
    29→        'Show me overdue invoices',
    30→        'How many team members do we have?',
    31→        'Show me open RFIs'
    32→      ]
    33→    };
    34→  }
    35→  const active     = rows.filter(r => r.status === 'active' || r.status === 'in_progress').length;
    36→  const completed  = rows.filter(r => r.status === 'completed').length;
    37→  const totalBudget = rows.reduce((s, r) => s + (parseFloat(r.budget) || 0), 0);
    38→  const totalSpent  = rows.reduce((s, r) => s + (parseFloat(r.spent)  || 0), 0);
    39→
    40→  let reply = `You have **${rows.length} projects** in total — ${active} active, ${completed} completed.\n`;
    41→  reply += `Combined budget: ${fmt(totalBudget)} | Spent so far: ${fmt(totalSpent)} (${pct(totalSpent, totalBudget)}%).\n\n`;
