    94→  ] as const;
    95→
    96→  return (
    97→    <div className="space-y-0">
    98→      {/* Breadcrumb */}
    99→      <div className="flex items-center gap-2 mb-4 text-sm">
   100→        <button onClick={onBack} className="flex items-center gap-1 text-gray-400 hover:text-white transition-colors">
